<?php
require_once __DIR__.'/../middleware/bootstrap.php';
function reloadly_token(){ $pdo=db();$row=$pdo->query("select * from reloadly_tokens order by id desc limit 1")->fetch();if($row&&strtotime($row['expires_at'])>time()+60)return $row['access_token'];$c=require __DIR__.'/../config/config.php';$ch=curl_init('https://auth.reloadly.com/oauth/token');curl_setopt_array($ch,[CURLOPT_RETURNTRANSFER=>1,CURLOPT_POST=>1,CURLOPT_HTTPHEADER=>['Content-Type: application/json'],CURLOPT_POSTFIELDS=>json_encode(['client_id'=>$c['reloadly']['client_id'],'client_secret'=>$c['reloadly']['client_secret'],'grant_type'=>'client_credentials','audience'=>'https://giftcards.reloadly.com'])]);$res=json_decode(curl_exec($ch),true);if(empty($res['access_token']))throw new Exception('Reloadly auth failed');$exp=date('Y-m-d H:i:s',time()+($res['expires_in']??3600));$st=$pdo->prepare('insert into reloadly_tokens(access_token,expires_at,created_at)values(?,?,now())');$st->execute([$res['access_token'],$exp]);return $res['access_token'];}
function reloadly_get($path){$c=require __DIR__.'/../config/config.php';$ch=curl_init($c['reloadly']['base'].$path);curl_setopt_array($ch,[CURLOPT_RETURNTRANSFER=>1,CURLOPT_HTTPHEADER=>['Authorization: Bearer '.reloadly_token(),'Accept: application/com.reloadly.giftcards-v1+json']]);$r=curl_exec($ch);return json_decode($r,true);} 
